SELECT [def01-qAcqEVend-Item-Union].*, Item.[Description 2], DatiCarryOverESMU.[Carry Over], DatiCarryOverESMU.Smu, Item.[Vendor No_] AS VendorCode, Vendor.Name AS Vendor, Item.[Trademark Code], Item.[Collection Code], Item.[Season Code], Item.[Line Code], IIf([QuantitySold]-[quantitypurchased]<0,[quantitysold]-[quantitypurchased],0) AS deltaPiazzarePairs, IIf([quantitysold]-[quantityPurchased]<0,[ValuePurchased]/[quantitypurchased]*[deltaPiazzarePairs],0) AS deltaPiazzareValueOLD, IIf([quantitysold]-[quantityPurchased]<0,[costo]*[deltaPiazzarePairs],0) AS deltaPiazzareValue, IIf([QuantitySold]-[QuantityPurchased]>0,[quantitySold]-[quantityPurchased],0) AS deltaComprarePairs, IIf([quantitysold]-[quantityPurchased]>0,[Valuepurchased]/[quantityPurchased]*[deltaComprarePairs],0) AS deltaComprareValueOLD, IIf([quantitysold]-[quantityPurchased]>0,[costo]*[deltaComprarePairs],0) AS deltaComprareValue, Item.[Season Typology], Item.[Product Family], Item.[Product Sex], Item.[Shipment Priority], Item.[Innovation Degree], Item.[Heel Height], Item.[End Customer Price Gap], Item.[Market Segment], Item.[Product Typology], Item.[Main Material], Item.[Sole Material], Item.[Must Buy], [quantitysold]-[deltacomprarepairs] AS SellablePairs, IIf([valuesold]<>0,[ValueSold]*[sellablePairs]/[quantitysold],0) AS SellableValue, IIf([pairssold]<>0,[grossSalesValue]*[sellablePairs]/[quantitysold],0) AS SellableGrossValue, IIf([quantitysold]<>0,[AreaManagerCommissionValue]*[sellablePairs]/[quantitysold],0) AS SellableAreaManagerCommissionValue, IIf([quantitysold]<>0,[SalesPersonCommissionValue]*[sellablePairs]/[quantitysold],0) AS SellableSalesPersonCommissionValue, IIf([quantitysold]<>0,[DiscountValue]*[sellablePairs]/[quantitysold],0) AS SellableDiscountValue, DatiCarryOverESMU.[Sold Out], DatiCarryOverESMU.[Sold Out Date], DatiCarryOverESMU.[Sales_Purchase Status Date]
FROM (([def01-qAcqEVend-Item-Union] INNER JOIN (Item LEFT JOIN Vendor ON Item.[Vendor No_] = Vendor.No_) ON [def01-qAcqEVend-Item-Union].Article = Item.No_) INNER JOIN DatiCarryOverESMU ON ([def01-qAcqEVend-Item-Union].ColorCode = DatiCarryOverESMU.[Variable Code 01]) AND ([def01-qAcqEVend-Item-Union].Article = DatiCarryOverESMU.[Model Item No_])) LEFT JOIN CostiAcquisti ON ([def01-qAcqEVend-Item-Union].taglia = CostiAcquisti.[Variable Code 02]) AND ([def01-qAcqEVend-Item-Union].Article = CostiAcquisti.[Model Item No_]) AND ([def01-qAcqEVend-Item-Union].ColorCode = CostiAcquisti.[Variable Code 01]);

